INSERT INTO membership_form (`Timestamp`,`Full_name_with_surname`,`Designation_in_your_business`,`Business_Name`,`Business_Category_i_e_IT_Construction_Travel_Automobile_etc`,`Mobile`,`Email`,`Business_Address`,`Address_Area_or_Location`,`City`,`Native_City`,`Birth_Date`,`Marriage_or_Anniversary_date`,`Brief_Business_Introduction`,`Profile_picture`,`Business_Logo`,`Attachment_of_Membership_Payment_Rs_1000`,`Residence_Address_Area_or_Location`,`Document_Save_In_Folder`) VALUES ('2025-10-13 14:58:26.995000','Harshad Rathod','Co-founder & Director ','Accretion Pharmaceuticals Limited & Accretion Nutraveda Limited','Healthcare (Pharmaceuticals Manufucturing )','9723755277.0','harshad11j@gmail.com','26-31 Xcelon Industrial Park- 1 , B/H intas Pharmaceuticals , Vasna-chacharvadi, Ta: Sanand , Dist: Ahmedabad 382213','Sanand ','Ahmedabad','Dhandhuka','1986-06-11 00:00:00','2011-12-06 00:00:00','From a spark of curiosity to a legacy of innovation—my journey in healthcare began with a simple belief: medicine has the power to transform lives.

I remember the thrill of discovering how a well-formulated drug could change a patient’s life, and that passion propelled me through my academic journey—earning a Bachelor of Pharmacy from LJ Institute of Pharmacy and later an MBA from Madhyanchal Professional University, Bhopal. These experiences laid the foundation for a career spanning over 14 years in the healthcare industry, where every challenge became an opportunity to innovate and lead.

In 2012, driven by a desire to revolutionize healthcare, I became one of the founding members of Accretion Pharmaceuticals, paving the way for innovation and excellence in the pharmaceutical industry. What started as a vision to deliver international-quality healthcare products has evolved into a thriving enterprise, dedicated to excellence and precision. Our early days were marked by bold initiatives and groundbreaking ideas, setting the stage for the transformative work we do today.

The journey didn’t stop there. In 2019, we expanded our horizons with the launch of Accretion INC, forging domestic collaborations that allowed our innovations to thrive across the country. Then, in March 2021, I ventured into the nutraceutical and wellness arena with Accretion Nutraveda Private Limited, diversifying our portfolio and reinforcing our commitment to holistic health solutions.

Today, I lead a passionate team in driving strategic financial management, operational efficiency, and business development. I oversee every facet of our operations—from meticulous financial planning and robust budgeting to ensuring our production processes and quality controls exceed global standards. Every decision, every process, is a step toward our goal of becoming a global leader in healthcare.

